var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"큭, 생각보다 저항이 거칠군.","JPN":"くっ、予想以上に抵抗が激しい。","ENG":"Kgh, they are resisting more than I had anticipated.","TWN":"唔，沒想到你們竟然如此頑強抵抗。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장! 이제 어떻게 할 거야? 경기 시간, 앞으로 40초 밖에 안 남았다고!","JPN":"副団長！　どうするつもり？　試合時間、あと40秒しかないよ！","ENG":"Deputy! What do we do now? There's only 40 seconds left on the clock!","TWN":"副團長！現在怎麼辦？時間只剩40秒！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 부단장님!! 시간이 없어요!!","JPN":"フィオネ副団長！！　時間がありません！！","ENG":"Deputy Fione!!! We're running out of time!!","TWN":"菲奧尼副團長！！沒時間了！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경, 한솔 경! 엄호하세요!","JPN":"アレン卿、ヤガミ卿！　援護を！","ENG":"Dame Liv, Sir Hansol! Cover me!","TWN":"莉芙卿、楊瀚卿！掩護我！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우리의 긍지를 위해서라도, 임무를 위해서라도 우리는 여기서 절대 물러설 수 없어요!","JPN":"私たちの誇りのためにも、任務のためにも、絶対ここで引くわけにはいきません！","ENG":"For our pride and for our mission! Retreating is absolutely unacceptable!","TWN":"為了我們的榮譽，或是為了任務也好，我們都絕對不能輸！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>무구</color>를 개방하겠습니다!","JPN":"<color=#ffd34c>武具</color>を開放します！","ENG":"I am going to unleash my <color=#ffd34c>Armament</color>!","TWN":"我要開放<color=#ffd34c>武具</color>！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐어!? 그건 너무 위험하지 않아!?","JPN":"はあ！？　それ、ヤバすぎない！？","ENG":"What?! But isn't that too dangerous?!","TWN":"什麼！？這樣不會太危險嗎！？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"최대한 파괴력을 억누르는데 집중할 겁니다! 그러기 위해선 시간이 필요해요!","JPN":"なるべく破壊力を抑えるのに集中します！　そのためには、時間が必要です！","ENG":"I'm going to focus all my powers on suppressing its destructiveness! But I will need time in order to do so!","TWN":"我會盡可能控制破壞力！所以我需要時間！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"정말 그래도 괜찮아? 아무리 억누른다고 해도, 카운터가 아니면 다칠지도 몰라!","JPN":"本当にそれでいいの？　いくら抑えるっていっても、カウンターじゃないと怪我するかもしれないんだよ！？","ENG":"Are you sure about this? Even if you suppress it, non-Counters might get hurt!","TWN":"真的沒關係嗎？不管怎麼控制，對方若不是制裁者很可能會受傷吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저 팀에는 카운터가 아닌 아이도 끼어 있다구!","JPN":"あのチームには、カウンターじゃない子もいる！","ENG":"There are non-Counters on the other team, you know!","TWN":"對方的隊伍裡也有不是制裁者的人欸！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브경, 이제까지 계속 버텨온 방패가 바로 그 아이입니다!","JPN":"アレン卿、今までずっと持ちこたえてきた盾がその子なのです！","ENG":"Dame Liv, that non-Counter is the shield that withstood all our attacks so far!","TWN":"莉芙卿，一直拿著盾牌誓死抵抗的就是那個孩子！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"최선을 다한 상대에게 부끄러운 승리를 넘겨주는 것은…… 기사단의 수치!","JPN":"最善を尽くした相手に恥ずかしい勝利を渡すのは……騎士団の恥！","ENG":"Handing over a shameful victory to an opponent who did their best... That is a disgrace to the Knights!","TWN":"她這麼努力，我要是將勝利就這樣拱手讓給她……這是身為騎士的羞恥！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"모두 조심하세요! 상대 측 리더가 뭔가를 준비하고 있습니다!","JPN":"みなさん、気をつけてください！　相手側のリーダーが何かを準備しています！","ENG":"Look alive, everyone! Their leader is preparing something!","TWN":"大家小心！對方的隊長好像預備要做什麼！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이런……! 꼬마 대장! 큰게 온다! 어서 뒤로 빠져!","JPN":"まずいぞ……！　チビ隊長！　何かが来る！　早く後ろに下がれ！","ENG":"Oh, bollocks...! Little Captain! Get back, now! Something big's coming!","TWN":"糟糕……！小不點隊長！有一波大的要來了！快退到後面！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"안 돼요! 디펜더인 제가 물러서면 바로 전열이 뚫린다고요!","JPN":"ダメです！　ディフェンダーの私が下がったら、すぐに突破されます！","ENG":"No! I'm the defender! If I don't stand my ground, then it's game over!","TWN":"不可以！我是負責防守的，要是我撤退的話，會立刻被攻破的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고 고작 30초 남았는데 여기서 물러설 수는 없어요!","JPN":"それにあと30秒なのに、ここで引くわけにはいきません！","ENG":"We only have 30 more seconds left! I can't retreat now!","TWN":"而且就只剩30秒，更不能就這樣撤退！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"앞으로 남은 시간 20초! 과연 카나리아 스쿼드는 승리를 지켜낼 수 있을 것인가!!","JPN":"残り時間、あと20秒！　果たしてカナリア・スクワッドは勝利を守れるか！！","ENG":"20 seconds remaining! Will Canary Squad be able to secure their win?!","TWN":"時間只剩20秒！究竟勝利女神是否會眷顧金絲雀小隊呢！！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"안 돼요! 피오네 언니!!","JPN":"ダメです！　フィオネさん！！","ENG":"No! FIONE!!","TWN":"不可以！菲奧尼姊姊！！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전갈자리의 기사, 피오네 로웰이 그대에게 묻겠다!","JPN":"蠍座の騎士、フィオネ・ローウェルがそなたに問う！","ENG":"Fione Lowell, the Knight of Scorpio, asks you!","TWN":"天蠍座騎士，菲奧尼·勞威爾問你！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그대들은 무엇을 위해 싸우는가!","JPN":"そなたらは何のために戦うのか！","ENG":"What do you fight for?!","TWN":"你們是為何而戰！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그대들은 어째서 나의 앞을 가로 막는가!","JPN":"そなたらは何故私の前に立ちふさがるのか！","ENG":"What are you standing in my way for?!","TWN":"為何要擋我去路！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭔가 잘 모르겠지만, 지금까지와는 분위기가 달라.","JPN":"何かよくわからないけど、今までとは雰囲気が違う。","ENG":"I don't know what exactly is going on, but something's different.","TWN":"雖然我也說不太清楚，但和之前的感覺不太一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저 사람이 비장의 수단을 쓴다면, 나에게도…….","JPN":"あの人が切り札を使うのなら、私にも……","ENG":"If she's going to use her ace up her sleeve, then I'll also have to–","TWN":"要是她使出絕招，那我也……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"하지만 여기서 그걸 쓰면, 오지만디아스에게 들키고 말아.","JPN":"でもここであれを使えば、オジマンディアスにバレてしまう。","ENG":"But if I use this right now, then Ozymandias will find out about it.","TWN":"但要是在這裡用的話，就會被奧茲曼迪亞斯發現。"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"쓰지 않는다면, 여기서 바로 패배하겠지.","JPN":"使わなかったら、ここで負けるわよね。","ENG":"If I don't, then I'll lose right here, right now.","TWN":"不用的話又會輸掉。"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇다면, 내가 해야 할 선택은……!","JPN":"それなら、私の選択は……！","ENG":"Then, my choice will be...!","TWN":"我到底該怎麼做……！"},"stage":{"bg":"CHARADE2_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"남은 시간 10초.","JPN":"残り時間10秒。","ENG":"10 seconds left.","TWN":"剩下10秒。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……어쩔거냐, 펠리세트.","JPN":"……どうするんだ？　フェリセット。","ENG":"...What's it gonna be, Félicette?","TWN":"……費莉塞特，你打算怎麼做？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭘 위해서 싸우냐고요?","JPN":"何のために戦ってるのかって聞きましたよね？","ENG":"What am I fighting for?","TWN":"你問我為何而戰？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……저는 이 지긋지긋한 도시가 싫어요.","JPN":"……私はこのうんざりした街が嫌いなんです。","ENG":"...I'm sick and tired of this city.","TWN":"……我討厭這座城市。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이 늪에서 벗어나기 위해 지금껏 발버둥쳤어요. 그걸 위해 지금껏 죽어라 노력해왔고요.","JPN":"この沼から出るために今まで足掻いてきました。そのために、今まで死ぬほど頑張ったんです。","ENG":"I've been trying to climb out of this mire since forever. And I've been putting my all into it.","TWN":"為了脫離這個泥沼，我一直拼命掙扎，拼命努力。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까……!","JPN":"だから……！","ENG":"That's why...!","TWN":"所以……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 당신들이 아무리 대단한 목적을 갖고 있다고 해도! 저는 절대 안 질 거에요!!","JPN":"だから、あなたたちがどれほど立派な目的を持っていたとしても！　私は絶対に負けられません！！","ENG":"That's why, even with your noble objectives! I will never lose!!","TWN":"我不管你們有多麼偉大的目標！我是絕對不會輸的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"절대로 양보 안 해!","JPN":"絶対譲らない！","ENG":"I will not yield!","TWN":"我絕不認輸！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"CARY_CHARADE_NPC_NULL","text":{"KOREA":"피오네, 겨우 이런 것도 똑바로 못하는 거야?","JPN":"フィオネ、こんなこともちゃんとできないの？","ENG":"Fione, why can't you even do this?","TWN":"菲奧尼，你連這個也做不好嗎？"},"stage":{"bg":"MANSION","bgm":"NEW_WORLD_INST","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARY_CHARADE_NPC_NULL","text":{"KOREA":"하여간 넌 정말, 로웰 가의 수치라니까.","JPN":"まったく、あんたは本当にローウェル家の恥なんだから。","ENG":"Seriously, you're a disgrace to our family.","TWN":"你真是勞威爾家族之恥！"},"stage":{"bg":"MANSION","bgm":"NEW_WORLD_INST","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BROWN_CHARADE_NPC_NULL","text":{"KOREA":"……피오네. 가문을 대표하는 기사가 되었으니 앞으로는 더욱 정진해야 할 거다.","JPN":"……フィオネ。家門を代表する騎士となったからには、これからもっと精進しなければならない。","ENG":"...Fione. Now that you've become the Knight of the family, you must work harder.","TWN":"……菲奧尼，既然你已經是代表家族的騎士，以後必須要更努力。"},"stage":{"bg":"MANSION","bgm":"NEW_WORLD_INST","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BROWN_CHARADE_NPC_NULL","text":{"KOREA":"이 애비는 이번 단장이 로웰 가문에서 나올 거라 믿어 의심치 않는다.","JPN":"父は、今度の団長がローウェル家から出ると信じている。","ENG":"I expect the next captain to be a Lowell.","TWN":"爸爸相信，新任的團長一定是出自我們勞威爾家族。"},"stage":{"bg":"MANSION","bgm":"NEW_WORLD_INST","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BROWN_CHARADE_NPC_NULL","text":{"KOREA":"……잘할 수 있겠지?","JPN":"……やれるな？","ENG":"...You won't disappoint me, will you?","TWN":"……你辦得到吧？"},"stage":{"bg":"MANSION","bgm":"NEW_WORLD_INST","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"경기 끝났습니다!","JPN":"試合終了です！","ENG":"The match is over!","TWN":"比賽結束！"},"stage":{"bg":"CITY_FLOAT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"승자는…… 카나리아 스쿼드!!","JPN":"勝者は……カナリア・スクワッド！！","ENG":"The winner is... CANARY SQUAD!!","TWN":"獲勝的是……金絲雀小隊！！"},"stage":{"bg":"CITY_FLOAT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"공격 팀, 조디악 나이츠의 공세를 성공적으로 방어합니다!!","JPN":"攻撃チーム、ゾディアックナイツの攻勢を見事防御しました！！","ENG":"They have successfully defended against the Zodiac Knights' offense!","TWN":"他們成功抵擋進攻方十二宮騎士團的攻勢！！"},"stage":{"bg":"CITY_FLOAT","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"후후, 펠리세트 양이라고 했나요?","JPN":"ふふ、フェリセットさんでしたか？","ENG":"Hah hah. Félicette, was it?","TWN":"呵呵，你叫費莉塞特嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저희의 패배입니다. 카운터도 아닌데, 정신력이 정말 대단하시군요.","JPN":"私たちの負けです。カウンターではないのに、素晴らしい精神力ですね。","ENG":"I admit defeat. You're not even a Counter, but you're mentally tougher than anyone else.","TWN":"我們認輸。雖然你不是制裁者，但耐力非常驚人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저…… 피오네 씨?","JPN":"あの……フィオネさん？","ENG":"Um... Miss Fione?","TWN":"那個……菲奧尼？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어째서 마지막에 공격을 포기하신 거예요?","JPN":"どうして最後に攻撃を諦められたんですか？","ENG":"Why did you stop your attack last second?","TWN":"為什麼你最後會選擇放棄攻擊呢？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저였다면, 그때…….","JPN":"私だったら、あの時……","ENG":"If it were me, I would've...","TWN":"要是我，那時候……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"샤레이드 건틀렛 리그는 원래 태스크포스 간의 실력 교류를 위해 만들어졌다고 하죠.","JPN":"シャレードのガントレットリーグはもともと、各タスクフォースの実力を確かめ合う場として開催されたと言われています。","ENG":"Charade's Gauntlet League was originally made to exchange skills among TASKFORCEs.","TWN":"查雷德聖鎧聯賽的目的是促進特遣勢力之間的實力交流。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?!","TWN":"什麼？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"공방을 주고받는 과정에서 부상은 있을 수 있지만, 기본적으로 비살상을 전제로 해요.","JPN":"攻防を交わす中で怪我することはありますが、基本的には非殺生が前提です。","ENG":"Although injuries may occur while teams attack and defend, the premise has always been not to kill.","TWN":"在彼此攻防的過程中，雖然不免會有受傷的可能，但基本上比賽的前提是禁止使用致命性武器的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"건틀렛의 역사가 지속된 이래로 많은 규칙이 바뀌었지만, 그것만큼은 달라지지 않았죠.","JPN":"長く続くガントレットの歴史の中で多くの規則が変わりましたが、これだけは変わりません。","ENG":"Many rule changes have been made in the Gauntlet's history, but this one has always remained.","TWN":"在聖鎧的歷史上，雖然曾經修改過幾次規則，但這一點是從未改變的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 무구를 개방한 시점에서 저희의 패배입니다.","JPN":"ですので、武具を開放した時点で私たちの負けです。","ENG":"So, when I decided to unleash my Armament, it was already our defeat.","TWN":"因此當我決定開放武具的瞬間，其實就表示我們已經輸掉比賽。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건 전장이 아닌 곳에서 사람을 겨눠서는 안 되는 물건이니까요.","JPN":"それは戦場以外で人に向けてはいけないものですから。","ENG":"That is something that should not be aimed at someone unless it is on the battlefield.","TWN":"因為那個東西只能被用在戰場上，而不是對準無辜的人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 점. 다시금 일깨워 주셔서 감사합니다, 펠리세트 양.","JPN":"その点。もう一度思い起こさせてくださったことに礼を言います。フェリセットさん。","ENG":"I want to thank you for reminding me of that fact, Félicette.","TWN":"謝謝你再次點醒我這一點，費莉塞特。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"흐응~ 아직도 그런 재미없는 소리를 하고 다니는 거야, 피오네?","JPN":"ふ～ん、まだそんなつまんないこと言っているの？　フィオネ。","ENG":"Hmm... Still going on about those boring things, I see, Fione.","TWN":"嗯哼～你還是很喜歡說教呢，菲奧尼？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어차피 건틀렛은 엔터테인먼트라고.","JPN":"どうせガントレットはエンターテインメントなのよ。","ENG":"Gauntlet is nothing but entertainment.","TWN":"總之聖鎧就是個娛樂節目。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그리고 비극은 언제나 가장 사랑받는 엔터테인먼트고.","JPN":"それに、悲劇はいつも一番人気のあるエンターテインメントだしね。","ENG":"And tragedies are always a beloved part of entertainment.","TWN":"而觀眾最愛看的就是灑狗血的悲劇。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"에리어스가 그렇게 판을 잘 깔아줬는데, 마지막에 경기를 말아먹으면 어떡하니?","JPN":"アリウスがあんなに頑張って煽ってくれたのに、最後に試合を台無しにしちゃダメじゃない。","ENG":"Arius had already laid out the perfect foundation, so how could you ruin it all last minute?","TWN":"埃里奧斯前面鋪成得那麼好，結果你最後卻搞砸這齣戲。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하여간 예술적 소양이 부족하다니까?","JPN":"まったく、芸術的素養が足りないんだから。","ENG":"I always knew you lacked artistic vision.","TWN":"怪只怪你藝術涵養不夠嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 네 언니였으면, 조금 더 재밌었을 텐데. 좀 아쉽네?","JPN":"ふふ、あなたのお姉さんだったらもっと面白かったのに。ちょっと残念だわ。","ENG":"Fu fuu. If it were your older sister, then things would've turned out interesting. What a shame, don't you think?","TWN":"呵呵，換你姊姊來演應該會更有趣吧？真可惜。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……오지만디아스!","JPN":"……オジマンディアス！","ENG":"...Ozymandias!","TWN":"……奧茲曼迪亞斯！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};